Script.script:
Tem = Tem or {}

Tem.ui = Tem.ui or {
  on = false,
  amorlbl = nil,
  honlbl = nil,
}

local MOON = 58
local MOON_GAP = 10
-- Inset from bottom-right (px): larger Y lifts moons above the status/input strip.
local MOON_INSET_X = 40
local MOON_INSET_Y = 52

local AMOR_MOON_CSS = [[
QLabel {
  background: qradialgradient(cx:0.32, cy:0.28, radius:0.95, fx:0.28, fy:0.24,
    stop:0 #ffffff, stop:0.35 #e6e6e6, stop:0.7 #a8a8a8, stop:1 #5c5c5c);
  border: 2px solid #b8b8b8;
  border-radius: 29px;
  color: #1a1a1a;
  font-size: 10px;
  font-weight: bold;
  padding: 2px;
  min-width: 58px;
  max-width: 58px;
  min-height: 58px;
  max-height: 58px;
}
]]

local HONESTUS_MOON_CSS = [[
QLabel {
  background: qradialgradient(cx:0.38, cy:0.30, radius:0.95, fx:0.32, fy:0.26,
    stop:0 #c9a8ff, stop:0.4 #7b4ec9, stop:0.75 #3d1f6e, stop:1 #1a0d33);
  border: 2px solid #9b6ee5;
  border-radius: 29px;
  color: #f0e8ff;
  font-size: 10px;
  font-weight: bold;
  padding: 2px;
  min-width: 58px;
  max-width: 58px;
  min-height: 58px;
  max-height: 58px;
}
]]

local function have_labels()
  return Tem.ui.amorlbl and Tem.ui.honlbl
end

local function safe_hide(label_name)
  if label_name then
    hideWindow(label_name)
  end
end

function Tem.uipos()
  if not have_labels() or not getMainWindowSize then
    return
  end
  local w, h = getMainWindowSize()
  if not w or not h then
    return
  end
  local hx = w - MOON_INSET_X - MOON
  local hy = h - MOON_INSET_Y - MOON
  local ax = hx - MOON_GAP - MOON
  moveWindow(Tem.ui.amorlbl, ax, hy)
  moveWindow(Tem.ui.honlbl, hx, hy)
end

function Tem.uiinit()
  if have_labels() then
    Tem.uipos()
    return true
  end

  Tem.ui.amorlbl = Tem.ui.amorlbl or "tempest_lunar_ui_amor"
  Tem.ui.honlbl = Tem.ui.honlbl or "tempest_lunar_ui_honestus"

  createLabel(Tem.ui.amorlbl, 0, 0, MOON, MOON, 1)
  createLabel(Tem.ui.honlbl, 0, 0, MOON, MOON, 1)

  setLabelStyleSheet(Tem.ui.amorlbl, AMOR_MOON_CSS)
  setLabelStyleSheet(Tem.ui.honlbl, HONESTUS_MOON_CSS)

  echo(Tem.ui.amorlbl, "Amor\n—")
  echo(Tem.ui.honlbl, "Honestus\n—")
  Tem.uipos()
  safe_hide(Tem.ui.amorlbl)
  safe_hide(Tem.ui.honlbl)

  if not Tem._uireshook and registerAnonymousEventHandler then
    Tem._uireshook = true
    registerAnonymousEventHandler("sysWindowResize", "Tem.uipos")
  end

  return true
end

function Tem.uishow()
  Tem.uiinit()
  Tem.ui.on = true
  Tem.uipos()
  showWindow(Tem.ui.amorlbl)
  showWindow(Tem.ui.honlbl)
end

function Tem.uihide()
  Tem.ui.on = false
  safe_hide(Tem.ui.amorlbl)
  safe_hide(Tem.ui.honlbl)
end

function Tem.uitog()
  if Tem.ui.on then
    Tem.uihide()
  else
    Tem.uishow()
  end
end

function Tem.uiamor(n)
  if not Tem.ui.on or not have_labels() then
    return
  end
  local v = tonumber(n)
  if not v then
    return
  end
  clearWindow(Tem.ui.amorlbl)
  echo(Tem.ui.amorlbl, string.format("Amor\n%d", v))
end

function Tem.uihon(n)
  if not Tem.ui.on or not have_labels() then
    return
  end
  local v = tonumber(n)
  if not v then
    return
  end
  clearWindow(Tem.ui.honlbl)
  echo(Tem.ui.honlbl, string.format("Honestus\n%d", v))
end
